import{_ as s,o as i,c as l,ag as e}from"./chunks/framework.CTpQozEL.js";const r=JSON.parse('{"title":"macOS에서 게이트웨이","description":"macOS에서 게이트웨이 런타임 (외부 launchd 서비스)","frontmatter":{"title":"macOS에서 게이트웨이","description":"macOS에서 게이트웨이 런타임 (외부 launchd 서비스)"},"headers":[],"relativePath":"platforms/mac/bundled-gateway.md","filePath":"platforms/mac/bundled-gateway.md","lastUpdated":null}'),n={name:"platforms/mac/bundled-gateway.md"};function t(h,a,p,d,c,o){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="macos에서-게이트웨이-외부-launchd" tabindex="-1">macOS에서 게이트웨이 (외부 launchd) <a class="header-anchor" href="#macos에서-게이트웨이-외부-launchd" aria-label="Permalink to &quot;macOS에서 게이트웨이 (외부 launchd)&quot;">​</a></h1><p>OpenClaw.app은 더 이상 Node/Bun 또는 게이트웨이 런타임을 번들로 제공하지 않습니다. macOS 앱은 <strong>외부</strong> <code>openclaw</code> CLI 설치를 기대하고, 게이트웨이를 자식 프로세스로 생성하지 않으며, 사용자별 launchd 서비스를 관리하여 게이트웨이를 실행 상태로 유지합니다 (또는 이미 실행 중인 로컬 게이트웨이가 있으면 연결합니다).</p><h2 id="cli-설치-로컬-모드에-필요" tabindex="-1">CLI 설치 (로컬 모드에 필요) <a class="header-anchor" href="#cli-설치-로컬-모드에-필요" aria-label="Permalink to &quot;CLI 설치 (로컬 모드에 필요)&quot;">​</a></h2><p>Mac의 기본 런타임은 Node 24입니다. 호환성을 위해 현재 <code>22.14+</code>인 Node 22 LTS도 작동합니다. 그런 다음 <code>openclaw</code>를 전역으로 설치하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>macOS 앱의 <strong>Install CLI</strong> 버튼은 앱이 내부적으로 사용하는 동일한 전역 설치 흐름을 실행합니다. npm을 먼저 선호하고, 그 다음 pnpm, 그런 다음 유일하게 감지된 패키지 관리자가 bun인 경우 bun을 사용합니다. Node는 권장 게이트웨이 런타임으로 유지됩니다.</p><h2 id="launchd-launchagent로서의-게이트웨이" tabindex="-1">Launchd (LaunchAgent로서의 게이트웨이) <a class="header-anchor" href="#launchd-launchagent로서의-게이트웨이" aria-label="Permalink to &quot;Launchd (LaunchAgent로서의 게이트웨이)&quot;">​</a></h2><p>레이블:</p><ul><li><code>ai.openclaw.gateway</code> (또는 <code>ai.openclaw.&lt;profile&gt;</code>; 레거시 <code>com.openclaw.*</code> 유지될 수 있음)</li></ul><p>Plist 위치 (사용자별):</p><ul><li><code>~/Library/LaunchAgents/ai.openclaw.gateway.plist</code> (또는 <code>~/Library/LaunchAgents/ai.openclaw.&lt;profile&gt;.plist</code>)</li></ul><p>관리자:</p><ul><li>macOS 앱은 로컬 모드에서 LaunchAgent 설치/업데이트를 소유합니다.</li><li>CLI도 설치할 수 있습니다: <code>openclaw gateway install</code>.</li></ul><p>동작:</p><ul><li>&quot;OpenClaw Active&quot;가 LaunchAgent를 활성화/비활성화합니다.</li><li>앱 종료로 게이트웨이가 중지되지 <strong>않습니다</strong> (launchd가 계속 실행).</li><li>구성된 포트에서 게이트웨이가 이미 실행 중이면 앱은 새 게이트웨이를 시작하는 대신 연결합니다.</li></ul><p>로깅:</p><ul><li>launchd stdout/err: <code>/tmp/openclaw/openclaw-gateway.log</code></li></ul><h2 id="버전-호환성" tabindex="-1">버전 호환성 <a class="header-anchor" href="#버전-호환성" aria-label="Permalink to &quot;버전 호환성&quot;">​</a></h2><p>macOS 앱은 게이트웨이 버전을 자체 버전과 비교합니다. 호환되지 않으면 전역 CLI를 앱 버전과 일치하도록 업데이트하십시오.</p><h2 id="스모크-체크" tabindex="-1">스모크 체크 <a class="header-anchor" href="#스모크-체크" aria-label="Permalink to &quot;스모크 체크&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_SKIP_CHANNELS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCLAW_SKIP_CANVAS_HOST=1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">openclaw </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loopback</span></span></code></pre></div><p>그런 다음:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://127.0.0.1:18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre></div>`,23)])])}const g=s(n,[["render",t]]);export{r as __pageData,g as default};
